import React, { useEffect } from 'react';
import AOS from 'aos';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faLaptopCode, faCodeBranch, faUsersCog, faChalkboardTeacher } from '@fortawesome/free-solid-svg-icons';

const Section = styled.section`
  padding: 100px 10%;
  text-align: center;
  position: relative;
  overflow: hidden;
`;

const Title = styled.h2`
  font-size: 2.5rem;
  color: #00FFFF;
  margin-bottom: 20px;
  position: relative;
  z-index: 2;

  &::after {
    content: '';
    display: block;
    width: 60px;
    height: 3px;
    background: linear-gradient(to right, #00FFFF, #00BFFF);
    margin: 10px auto;
  }
`;

const Cards = styled.div`
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 30px;
  margin-top: 50px;
`;

const Card = styled.div`
  background: rgba(255, 255, 255, 0.05);
  border-radius: 20px;
  padding: 40px 30px;
  width: 280px;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: transform 0.3s ease, box-shadow 0.3s ease;

  &:hover {
    transform: translateY(-10px);
    box-shadow: 0 15px 30px rgba(0, 255, 255, 0.1);
  }

  i {
    font-size: 2.5rem;
    color: #00FFFF;
    margin-bottom: 20px;
  }

  h3 {
    font-size: 1.5rem;
    color: white;
    margin: 15px 0;
  }

  p {
    color: rgba(255, 255, 255, 0.8);
    line-height: 1.6;
  }
`;

const Highlights = () => {
  useEffect(() => {
    AOS.init({
      duration: 800,
      once: true
    });
  }, []);

  const highlights = [
    {
      icon: faLaptopCode,
      title: "Workshops",
      description: "Hands-on learning in Web, AI, IoT & more. Master new skills with expert guidance."
    },
    {
      icon: faCodeBranch,
      title: "Hackathons",
      description: "Innovate & compete in exciting challenges. Turn ideas into reality in 48 hours."
    },
    {
      icon: faUsersCog,
      title: "Team Projects",
      description: "Build real-world solutions together. Collaborate and create impactful projects."
    },
    {
      icon: faChalkboardTeacher,
      title: "Tech Talks",
      description: "Sessions with industry experts & alumni. Learn from the best in the field."
    }
  ];

  return (
    <Section id="highlights">
      <Title data-aos="fade-up">What We Do</Title>
      <Cards>
        {highlights.map((item, index) => (
          <Card
            key={index}
            data-aos="fade-up"
            data-aos-delay={100 * (index + 1)}
          >
            <FontAwesomeIcon icon={item.icon} size="2x" color="#00FFFF" />
            <h3>{item.title}</h3>
            <p>{item.description}</p>
          </Card>
        ))}
      </Cards>
    </Section>
  );
};

export default Highlights;
